import React from "react";
import AnimatedCursor from "react-animated-cursor";

export const Cursor = () => {
  return (
    <div>
      <AnimatedCursor
        color="255,255,255"
        innerSize={20}
        outerSize={45}
        outerScale={2}
        innerScale={3}
        innerStyle={
            {mixBlendMode: 'exclusion'}
        }
        outerAlpha={0}
        outerStyle={{
            border: "3px solid #fff",
            mixBlendMode: 'exclusion'
        }}
        clickables={[
            'a',
            'input[type="text"]',
            'input[type="email"]',
            'input[type="number"]',
            'input[type="submit"]',
            'input[type="image"]',
            'label[for]',
            'select',
            'textarea',
            'button',
            '.link',
            '.clickable'
          ]}
       
      />
    </div>
  );
};
