import React, { useEffect, useState } from "react";

// LIBRARIES
import Fade from "react-reveal/Fade";
// COMPONENTS
import wave from "../IMGS/wave.svg";
import waveTwo from "../IMGS/wave-2.svg";
import noise from "../IMGS/noise.7f2f5230.png";
import francisco from "../IMGS/profile.jpg";
import github from "../IMGS/github.png";
import CV from "../FranciscoAgustinRodriguez-CV.pdf";

export const About = () => {
  // SCROLL VIEWER
  const [offsetX, setOffsetX] = useState(0);
  const handleScroll = () => setOffsetX(window.pageYOffset);
  useEffect(() => {
    window.addEventListener("scroll", handleScroll);

    return () => window.removeEventListener("scroll", handleScroll);
  }, []);

  // MAKE IMGS FOLLOW CURSOR
  var cursor = document.querySelector(".follow-img");
  var kursor = document.querySelector(".github");
  document.addEventListener("mousemove", (e) => {
    var x = e.clientX;
    var y = e.clientY;
    cursor.style.left = `${x}px`;
    cursor.style.top = `${y}px`;
    kursor.style.left = `${x}px`;
    kursor.style.top = `${y}px`;
  });

  return (
    <div className="h-[100vh] mb-[3rem] relative bg-[#DCD8D7] z-0 m-7 smartphone:m-0 smartphone:h-[80vh] tablet:h-[100vh]">
      <img src={noise} className="absolute h-[100%] w-[100%] " />
      <img src={wave} className="absolute w-[100%] top-[-1px] z-0" />

      <div
        className="mb-[1rem]"
        style={{ transform: `translateY(${offsetX * 0.36}px)` }}
      >
        <h1 className="relative text-[#232323] text-[15rem] mt-[30rem] text-center -top-[15rem] tracking-tighter z-0 Bogart select-none smartphone:text-[6.5rem] smartphone:pr-1 tablet:text-[9rem] laptop:text-[12rem] ">
          About
        </h1>
      </div>

      <div className=" relative z-0 text-center smartphone:text-left smartphone:pl-2 select-none">
        <Fade bottom delay={200}>
          <div className="mt-[10rem] relative text-[#3D3D3D] font-light text-[3.8em] Raleway smartphone:text-[1.8rem] smartphone:mt-[4rem] tablet:text-[2.9em] tablet:mt-[5.5rem] laptop:text-[3.2em] laptop:mt-[5.5rem]">
            <p className="mb-[-16rem] relative smartphone:mb-[-15rem] ">
              Hello, I'm
              <span
                id="a-name"
                className="about_info Bogart font-semibold text-[#DA5844] hover:text-[#BB3925] p-4 pb-0 pr-0 text-[4.5rem] z-50 transition-all duration-200 smartphone:text-[2.2rem] tablet:text-[3.5rem] laptop:text-[3.5rem]"
              >
                <a
                  href={CV}
                  target="_blank"
                  rel="noopener noreferrer"
                  className=""
                >
                  Francisco Agustín Rodríguez
                </a>
              </span>
              .
              <img src={francisco} className="follow-img transition-all " />
            </p>
            <p className="mb-[-16rem] relative smartphone:mb-[-12rem] tablet:mb-[-15rem]">
              Self taught
              <span
                id="a-gh"
                className="about_info text-[4.5rem] Bogart text-[#DA5844] hover:text-[#BB3925] font-semibold  p-4 pr-0 pb-0 transition-all duration-200 smartphone:text-[2.2rem] tablet:text-[3.5rem] laptop:text-[3.5rem]"
              >
                <a
                  href="https://github.com/franciscoagustinr"
                  target="_blank"
                  rel="noopener noreferrer"
                >
                  Web developer{" "}
                </a>
              </span>
              —focused on <span className="">frontend</span>.
              <img src={github} className="github follow-img" />
            </p>
            <br />
            <p className="relative">Based in Buenos Aires, Argentina.</p>
          </div>
        </Fade>
        <img
          src={waveTwo}
          className="absolute w-[100%] top-[95%]  z-0 smartphone:left-0 smartphone:top-[30.5rem] tablet:top-[41rem] laptop:top-[25rem]"
          style={{ transform: `translateY(-${offsetX * 0.09}px)` }}
        />
      </div>
    </div>
  );
};
