import React, { useEffect } from "react";

// LIBRARIES
import Fade from "react-reveal/Fade";

export const Header = () => {
  const scrollToContact = () => {
    window.scrollTo({
      top: 4200,
      behavior: "smooth",
    });
  };

  useEffect(() => {
    var textMove = document.querySelector(".textMove");
    document.addEventListener("mousemove", (e) => {
      var x = e.clientX;
      var y = e.clientY;
      textMove.style.left = `${x / 50}px`;
      textMove.style.top = `${y / 50}px`;
    });
  }, []);

  return (
    <div className="h-[50vh] relative bg-[#222322] z-50 smartphone:h-[35vh] select-none">
      <div className="relative left-[10%] top-[20%] laptop:left-[5%] ">
        <Fade top>
          <h3 className="  text-[#fafafa] Albert text-xl opacity-[.9] smartphone:text-lg smartphone:-ml-6 tablet:-ml-6">
            Hi <span className="text-2xl smartphone:text-xl">👋</span> I'm
          </h3>
        </Fade>

        <Fade right >
          <div>

          <h1 className="gradient-text textMove relative -ml-4 mt-4 mb-7  text-[11em] Bogart tracking-wide leading-none smartphone:text-[3.5em] smartphone:-ml-7 tablet:text-[6.5em] tablet:-ml-7 laptop:text-[8.5em]">
            Francisco A. <br />
            Rodríguez
          </h1>
          </div>
        </Fade>

        <Fade bottom delay={900}>
          <div className="slots Bogart font-thin text-[#fafafa] text-[2em] mt-7 smartphone:-ml-6 smartphone:mt-16 smartphone:text-[1.3em] tablet:-ml-6">
            <div className="flex flex-row">
              <p className="char">F</p>
              <p className="char ">R</p>
              <p className="char ">O</p>
              <p className="char ">N</p>
              <p className="char ">T</p>
              <p className="char ">E</p>
              <p className="char ">N</p>
              <p className="char ">D</p>
              <span className="ml-4"> </span>
              <p className="char ">D</p>
              <p className="char ">E</p>
              <p className="char ">V</p>
              <p className="char ">E</p>
              <p className="char ">L</p>
              <p className="char ">O</p>
              <p className="char">P</p>
              <p className="char ">E</p>
              <p className="char ">R</p>
              <p className="balloon text-[2.8rem] smartphone:text-[2rem]">🎈</p>
            </div>
          </div>
        </Fade>

        <Fade left>
          <div className="button-cont mt-10 ">
            <button
              onClick={scrollToContact}
              className=" ring-2 hover:ring-0 p-2 mt-4 relative w-[150px] bg-[#00c4ff] hover:bg-[transparent] text-[#111111] hover:text-[#fafafa] border-2 border-[#00c4ff] hover:border-[#fafafa] transition-all duration-[400ms] font-semibold cursor-none Albert tracking-wider rounded-[30px] uppercase z-50 smartphone:mt-10 smartphone:ml-[4.5rem] tablet:-ml-6"
            >
              <p>Hire me!</p>
            </button>
          </div>
        </Fade>
      </div>
    </div>
  );
};
