import React, { useRef } from 'react'

// LIBRERIES
import emailjs from "@emailjs/browser";
import Slide from "react-reveal/Slide";
import swal from 'sweetalert';



export const ContactForm = () => {



    // FORM
    const form = useRef();
    function sendEmail(e) {
      e.preventDefault();
      emailjs
        .sendForm(
          "service_034cv8n",
          "template_mjzfvxm",
          form.current,
          "YlfSI4SIEKgSzezN5"
        )
        .then(
          (response) => {
            console.log("SUCCESS!", response.status, response.text);
          },
          (err) => {
            console.log("FAILED...", err);
          }
        );

        setTimeout(() => {
            return swal("Thanks!", "Mail sended!", "success");
          }, 300);
    }

return (
    <div className='contactFormContainer overflow-hidden'>

        <Slide left>
          <div className=" circle-dance absolute left-[63%] top-[85%] z-0 bg-[#BB3925] w-[220px] h-[220px] rounded-[100%]  transition-all  smartphone:top-[40%] smartphone:left-[5%] tablet:top-[50%] tablet:left-[15%]"/>
        </Slide>

        <Slide right>
          <div className=" circle-dance absolute left-[25%] top-[55%] z-0 bg-[#BB3925] w-[350px] h-[350px] rounded-[100%]  transition-all  smartphone:hidden smartphone:left-[5%] tablet:top-[75%] tablet:left-[50%]"/>
        </Slide>
      
        
        <Slide bottom>
         <div className="card-container w-[100%] mt-[5rem] z-50 relative">
           <div className="card flex align-center gap-[2rem] justify-center  ">
             <form ref={form} onSubmit={sendEmail} 
             className="w-[45%] glass Raleway text-[#111111] tracking-wide smartphone:w-[100%] smartphone:m-2  smartphone:p-2 tablet:w-[85%] tablet:m-2 tablet:p-2" >
               <div className="m-4 p-7 flex flex-col align-center justify-center border-[3px] border-[#474544] smartphone:m-2 smartphone:p-2" >
                 <h3 className="text-center m-4 text-[2.5em]  Bogart text-[#3D3D3D]  smartphone:text-[1.7em] smartphone:m-2 smartphone:mb-7" >
                   •{" "}
                   <span className="font-extrabold uppercase tracking-wider select-none">
                     Keep in touch
                   </span>{" "}
                   •
                 </h3>
                 <div className="m-[1rem] flex flex-col">
                   <input name="user_name" type="text" 
                     placeholder="MY NAME"
                     required
                     minlength="3" 
                     className="input_field mt-1 p-2 bg-transparent border-b-2 border-[#474544] placeholder-gray-900 placeholder-opacity-70  text-[1rem]"
                   />
                 </div>
                 <div className="m-[1rem] flex flex-col">
                   <input name="user_email" type="text"
                     placeholder="MY MAIL"
                     required
                     minlength="3" 
                     className="input_field mt-1 p-2 bg-transparent border-b-2 border-[#474544] placeholder-gray-900 placeholder-opacity-70 text-[1rem]"
                   />
                </div>

                 <div className="m-[1rem] mb-[2.5rem] flex flex-col">
                   <textarea name="message"
                     placeholder="WRITE A MESSAGE"
                     required
                     minlength="1" 
                     className="input_field mt-1 p-2 bg-transparent border-b-2 border-[#474544] placeholder-gray-900 placeholder-opacity-70 text-[1rem] h-[10rem]"
                   />
                 </div>

                 <input type="submit" value="send!"
                   className="ring-0 hover:ring-2 p-2 mt-4 m-auto w-[150px] bg-[transparent] hover:bg-[#00c4ff] text-[#111111] hover:text-[#fafafa] border-2 border-[#fafafa] hover:border-[#00c4ff] transition-all duration-[400ms] font-semibold cursor-none Albert tracking-wider rounded-[30px] uppercase z-50 hover:scale-125 smartphone:mb-4"
                 />
               </div>
             </form>
           </div>
         </div>
        </Slide>
        
     </div>
)
}
