import React, { useEffect, useState } from "react";

// LIBRARIES
import Fade from "react-reveal/Fade";
import Slide from "react-reveal/Slide";

export const Works = () => {
  const [offsetX, setOffsetX] = useState(0);
  const handleScroll = () => setOffsetX(window.pageYOffset);

  useEffect(() => {
    window.addEventListener("scroll", handleScroll);
    return () => window.removeEventListener("scroll", handleScroll);
  }, []);

  const works = [
    {
      // imageURL: require("../IMGS/disneyClone.jpg"),
      url: "https://shurikenleapgame.netlify.app/",
      name: "Shuriken Leap Game",
      description: "A game created with React Three Fiber (ThreeJS)",
      technologies: "REACTJS + TAILWINDCSS + THREEJS / R3F ",
      id: "1",
    },
    {
      // imageURL: require("../IMGS/disneyClone.jpg"),
      url: "https://sage-beignet-1e7e8a.netlify.app/",
      name: "Crypcoll Crypto Trade",
      description: "Concept landingpage for Crypcoll crypto trades",
      technologies: "REACTJS + TAILWINDCSS + THREEJS / R3F",
      id: "2",
    },
    {
      // imageURL: require("../IMGS/disneyClone.jpg"),
      url: "https://eloquent-klepon-12b92d.netlify.app/",
      name: "Luvly",
      description: "Landingpage presentation for Luvly, the eco car ",
      technologies: "REACTJS + TAILWINDCSS + THREEJS / R3F",
      id: "3",
    },
    {
      imageURL: require("../IMGS/disneyClone.jpg"),
      url: "https://leafy-gingersnap-887f3e.netlify.app/",
      name: "Disney+ Clone",
      description: "Based on Disney+ Consumes the data of TMDB Api.",
      technologies: "REACTJS + TAILWINDCSS",
      id: "4",
    },
    {
      imageURL: require("../IMGS/NetflixChallenge.jpg"),
      url: "https://effortless-pavlova-52c33e.netlify.app/",
      name: "Netflix Search Clone",
      description:
        "A simple Netflix search clone. Uses IMDB API to search movie or serie by title and display them with the info.",
      technologies: "REACTJS + TAILWINDCSS",
      id: "5",
    },

    {
      imageURL: require("../IMGS/RMR.jpg"),
      url: "https://dulcet-mandazi-5ba759.netlify.app/",
      name: "RMR || Locutor ",
      description:
        "My first project: a simple page where the announcer Ricardo M. Rodríguez show his voice to the world.",
      technologies: "HTML + CSS + JS",
      id: "6",
    },
  ];

  return (
    <div className="relative z-50 select-none">
      <Slide right>
        <h1 className="z-50 Bogart text-[16em] text-left ml-[-4rem] gradient-text smartphone:text-[8em]  ">
          Works
        </h1>
      </Slide>
      {/* PROJECTS CONTAINER */}
      <div className="mt-[1em] w-11/12 flex flex-col items-center justify-center">
        {works &&
          works.map((work) => {
            // ADJUST POSITION ::: LEFT OR RIGHT BY ID
            const workId = work.id;
            const positionProject =
              workId % 2 === 0 ? { marginLeft: "-10%" } : { marginLeft: "35%" };
            const positionTitle =
              workId % 2 === 0 ? { textAlign: "left" } : { textAlign: "right" };

            return (
              // EACH PROJECT
              <Fade bottom>
                <div
                  key={work.id}
                  className="work-box parent flex flex-col relative m-[2.5em] w-[53%] p-10  rounded-2xl smartphone:w-[100%] smartphone:m-4 "
                  style={{ ...positionProject }}
                >
                  <div
                    className="relative project scale-95 hover:scale-110 transition-all duration-[.5s] "
                    style={{ ...positionTitle }}
                  >
                    <div
                      className="circle absolute  top-[5%] z-[-10] bg-[#BB3925] w-[180px] h-[180px] rounded-[100%] transition-all duration-[.5s]"
                      style={{ ...positionProject }}
                    />
                    <a
                      href={work.url}
                      target="_blank"
                      rel="noopener noreferrer"
                      className="grayscale-[80%] hover:grayscale-0 z-50"
                    >
                      {/* <img src={work.imageURL} key={work.id} alt={work.name} className="workImg "/> */}
                      <p className="work-title text-[3.5rem] text-[#F8B400] drop-shadow-lg Bogart z-50 smartphone:text-[2rem] tablet:text-[2.5rem] ">
                        {work.name}
                      </p>
                      <p className="text-[1.1rem] mt-1 text-[#F2EEE9] z-50 Raleway">
                        {work.description}
                      </p>
                      <p className="text-[.8rem] font-bold mt-1 text-[#F2EEE9] tracking-wide Raleway z-50">
                        {work.technologies}
                      </p>
                    </a>
                  </div>
                </div>
              </Fade>
            );
          })}
      </div>
    </div>
  );
};
